컷씬 도중 플레이어 모델이 보이는 문제와 종료 후 카메라가 작동하지 않는 문제는 **`CutsceneManager`가 씬 로딩 초기 단계(Awake)에서 오브젝트를 제대로 찾지 못해 참조가 비어있기 때문**입니다.

특히 `scene.isLoaded` 체크 로직이 씬이 완전히 로드되기 전인 `Awake` 타이밍에는 `false`를 반환하여 탐색을 건너뛰는 부작용이 있었습니다. 또한, 컷씬용 모델이 활성화될 때 조작용 모델이 확실히 꺼지도록 "태그 기반 일괄 비활성화"라는 안전장치를 추가하겠습니다.

### **수정 계획**

1.  **참조 탐색 조건 완화:** `scene.isLoaded` 체크를 제거하여 `Awake` 시점에도 오브젝트를 찾을 수 있게 합니다.
2.  **플레이어 노출 방지 (강력한 조치):** `StartCutscene` 호출 시 태그가 `Player`인 모든 오브젝트(조작용 모델 포함)를 전수 조사하여 컷씬 모델을 제외하고 모두 비활성화합니다.
3.  **카메라 시스템 복구 강화:** `EndCutscene` 시 메인 카메라의 `CinemachineBrain`이 켜져 있는지 확인하고, 게임플레이 카메라의 우선순위를 높여 화면 전환을 강제합니다.

### **파일 수정: Assets/Scripts/Managers/CutsceneManager.cs**

```csharp
using UnityEngine;
using UnityEngine.SceneManagement;
using Unity.Cinemachine;

namespace VanzAI.Managers
{
    public class CutsceneManager : MonoBehaviour
    {
        private static CutsceneManager _instance;
        public static CutsceneManager Instance
        {
            get
            {
                if (_instance == null)
                {
                    _instance = Object.FindFirstObjectByType<CutsceneManager>();
                    if (_instance == null)
                    {
                        GameObject go = new GameObject("CutsceneManager");
                        _instance = go.AddComponent<CutsceneManager>();
                    }
                }
                return _instance;
            }
        }

        [Header("Settings")]
        [SerializeField] private GameObject gameplayPlayer;
        [SerializeField] private CinemachineCamera mainGameplayCamera;

        private GameObject _activeCutscenePlayer;

        private void Awake()
        {
            if (_instance != null && _instance != this)
            {
                Destroy(gameObject);
                return;
            }
            _instance = this;
            DontDestroyOnLoad(gameObject);
            ResolveSceneReferences();
        }

        private void OnEnable() => SceneManager.sceneLoaded += OnSceneLoaded;
        private void OnDisable() => SceneManager.sceneLoaded -= OnSceneLoaded;

        private void OnSceneLoaded(Scene scene, LoadSceneMode mode)
        {
            _activeCutscenePlayer = null;
            gameplayPlayer = null;
            mainGameplayCamera = null;
            ResolveSceneReferences();

            if (gameplayPlayer != null && _activeCutscenePlayer == null)
            {
                gameplayPlayer.SetActive(true);
            }
        }

        private void ResolveSceneReferences()
        {
            var scene = SceneManager.GetActiveScene();
            // scene.isLoaded 체크를 제거하여 Awake/Start 시점에도 탐색 허용
            var roots = scene.GetRootGameObjects();

            if (gameplayPlayer == null)
            {
                foreach (var root in roots)
                {
                    if (root.name == VanzConstants.PlayerModelName) { gameplayPlayer = root; break; }
                    var found = FindChildRecursive(root.transform, VanzConstants.PlayerModelName);
                    if (found != null) { gameplayPlayer = found.gameObject; break; }
                }
            }

            if (mainGameplayCamera == null)
            {
                foreach (var root in roots)
                {
                    var found = FindChildRecursive(root.transform, VanzConstants.GameplayCameraName);
                    if (found != null) { mainGameplayCamera = found.GetComponent<CinemachineCamera>(); break; }
                }
            }
        }

        public void StartCutscene(GameObject cutscenePlayer)
        {
            // 무조건 최신 참조를 다시 확인
            ResolveSceneReferences();
            _activeCutscenePlayer = cutscenePlayer;

            // 1. 모든 'Player' 태그 오브젝트를 찾아 비활성화 (컷씬 모델 제외)
            var allPlayers = GameObject.FindGameObjectsWithTag(VanzConstants.PlayerTag);
            foreach (var p in allPlayers)
            {
                if (p != _activeCutscenePlayer)
                {
                    p.SetActive(false);
                    Debug.Log($"[CutsceneManager] Hidden gameplay player: {p.name}");
                }
            }

            // 2. 컷씬 모델 활성화 및 위치 동기화
            if (_activeCutscenePlayer != null)
            {
                if (gameplayPlayer != null)
                {
                    _activeCutscenePlayer.transform.position = gameplayPlayer.transform.position;
                    _activeCutscenePlayer.transform.rotation = gameplayPlayer.transform.rotation;
                }
                _activeCutscenePlayer.SetActive(true);
            }
        }

        public void EndCutscene(GameObject cutsceneActor = null)
        {
            ResolveSceneReferences();
            var finalActor = cutsceneActor ?? _activeCutscenePlayer;

            if (gameplayPlayer != null)
            {
                if (finalActor != null)
                {
                    var cc = gameplayPlayer.GetComponent<CharacterController>();
                    if (cc != null) cc.enabled = false;

                    gameplayPlayer.transform.position = finalActor.transform.position;
                    gameplayPlayer.transform.rotation = finalActor.transform.rotation;

                    if (cc != null) cc.enabled = true;
                    finalActor.SetActive(false);
                }
                gameplayPlayer.SetActive(true);
            }

            // --- 카메라 복구 로직 ---
            if (mainGameplayCamera != null)
            {
                mainGameplayCamera.gameObject.SetActive(true);

                Transform target = FindChildRecursive(gameplayPlayer.transform, VanzConstants.PlayerCameraRootName);
                if (target == null && gameplayPlayer != null) target = gameplayPlayer.transform;

                if (target != null)
                {
                    mainGameplayCamera.Follow = target;
                    mainGameplayCamera.LookAt = target;
                }

                // 우선순위를 높여 화면 전환 강제
                mainGameplayCamera.Priority = 100;

                // CinemachineBrain 활성화 확인
                var brain = Camera.main?.GetComponent<CinemachineBrain>();
                if (brain != null) brain.enabled = true;

                Debug.Log("[CutsceneManager] Gameplay Camera Restored.");
            }

            _activeCutscenePlayer = null;
        }

        private static Transform FindChildRecursive(Transform parent, string name)
        {
            if (parent == null) return null;
            if (parent.name == name) return parent;
            for (int i = 0; i < parent.childCount; i++)
            {
                var deep = FindChildRecursive(parent.GetChild(i), name);
                if (deep != null) return deep;
            }
            return null;
        }
    }
}
```

### **왜 이 수정이 효과적인가요?**

1.  **노출 문제 해결:** `GameObject.FindGameObjectsWithTag`를 사용하여 씬에 있는 모든 'Player' 태그 객체를 찾아 비활성화합니다. 이름 기반 탐색(`gameplayPlayer`)이 실패하더라도 태그 기반으로 확실히 숨깁니다.
2.  **카메라 작동 보장:**
    *   `Priority = 100`으로 설정하여 타임라인 카메라보다 우선권을 가져옵니다.
    *   `CinemachineBrain`을 다시 확인하여 활성화합니다.
    *   `mainGameplayCamera.gameObject.SetActive(true)`로 카메라 자체가 꺼져 있는 상황을 방지합니다.
3.  **참조 누락 방지:** `isLoaded` 조건을 제거하여 씬이 로딩 중인 `Awake` 타이밍에도 `Player_Model`을 찾아낼 수 있도록 개선했습니다.

이 코드를 적용하시겠습니까? (에이전트에게 **"매니저 코드 업데이트해줘"**라고 하시면 즉시 반영됩니다.)

컷씬 도중 플레이어 모델이 계속 노출되는 문제는 **타임라인(Timeline)의 'Activation Track'이 `CutsceneManager`의 비활성화 명령보다 나중에 실행되어 플레이어를 다시 강제로 켜기 때문**일 가능성이 매우 높습니다.

특히 인트로 시퀀스 타임라인에 플레이어 모델이 바인딩되어 있다면, 타임라인이 재생되는 순간 `SetActive(true)`가 호출되어 매니저의 설정을 무시하게 됩니다.

이를 해결하기 위해 **가장 확실한 방법은 플레이어를 단순히 끄는 것이 아니라, 씬의 멀리 떨어진 '대기 구역'으로 잠시 옮겨버리는 것**입니다. 이렇게 하면 타임라인이 플레이어를 활성화하더라도 카메라에 잡히지 않습니다.

### **수정 계획**

1.  **임시 유폐(Teleport Away):** 컷씬 시작 시 플레이어를 매우 먼 좌표(예: `Vector3.down * 1000`)로 이동시키고 비활성화합니다.
2.  **타겟 제거:** 컷씬 도중에는 메인 카메라의 `Follow/LookAt` 타겟을 `null`로 만들어 카메라가 플레이어를 쫓아가지 않게 합니다.
3.  **복구 시점 정밀화:** `EndCutscene`에서만 플레이어를 원래 위치(컷씬 종료 지점)로 불러오고 활성화합니다.

### **파일 수정: Assets/Scripts/Managers/CutsceneManager.cs**

```csharp
// Assets/Scripts/Managers/CutsceneManager.cs 수정본 핵심 부분

        public void StartCutscene(GameObject cutscenePlayer)
        {
            ResolveSceneReferences();
            _activeCutscenePlayer = cutscenePlayer;

            // 1. 모든 'Player' 태그 오브젝트를 찾아 멀리 유폐 (타임라인 강제 활성화 대비)
            var allPlayers = GameObject.FindGameObjectsWithTag(VanzConstants.PlayerTag);
            foreach (var p in allPlayers)
            {
                if (p != _activeCutscenePlayer)
                {
                    // 위치를 지하 깊숙이 옮겨서 타임라인이 켜더라도 안 보이게 함
                    p.transform.position += Vector3.down * 500f; 
                    p.SetActive(false);
                }
            }

            // 2. 컷씬 모델 활성화 및 위치 동기화
            if (_activeCutscenePlayer != null)
            {
                // 게임플레이 플레이어의 '원래' 위치(유폐 전)를 찾기 위해 
                // gameplayPlayer 참조가 살아있다면 그 위치를 사용
                if (gameplayPlayer != null)
                {
                    // 이미 유폐되었다면 위치값이 오염되었을 수 있으므로 
                    // 컷씬 시작 시점의 위치 동기화는 컷씬 모델이 배치된 자리를 우선함 (또는 특정 좌표)
                    _activeCutscenePlayer.SetActive(true);
                }
                else
                {
                    _activeCutscenePlayer.SetActive(true);
                }
            }

            // 3. 게임플레이 카메라 타겟 해제 (컷씬 도중 튀는 현상 방지)
            if (mainGameplayCamera != null)
            {
                mainGameplayCamera.Follow = null;
                mainGameplayCamera.LookAt = null;
            }
        }

        public void EndCutscene(GameObject cutsceneActor = null)
        {
            ResolveSceneReferences();
            var finalActor = cutsceneActor ?? _activeCutscenePlayer;

            if (gameplayPlayer != null)
            {
                // 유폐되었던 플레이어를 불러오기 전에 CharacterController 끄기
                var cc = gameplayPlayer.GetComponent<CharacterController>();
                if (cc != null) cc.enabled = false;

                if (finalActor != null)
                {
                    // 컷씬 모델의 최종 위치로 소환
                    gameplayPlayer.transform.position = finalActor.transform.position;
                    gameplayPlayer.transform.rotation = finalActor.transform.rotation;
                    finalActor.SetActive(false);
                }
                else
                {
                    // 컷씬 모델이 없다면 지하에서 지상(0,0,0 혹은 마지막 유효 위치)으로 복귀
                    // 이 부분은 프로젝트의 기본 스폰 위치 등으로 보정 가능
                    gameplayPlayer.transform.position += Vector3.up * 500f;
                }

                if (cc != null) cc.enabled = true;
                gameplayPlayer.SetActive(true);
            }

            // 카메라 복구 로직 (기존과 동일하되 타겟 재연결 보장)
            if (mainGameplayCamera != null)
            {
                mainGameplayCamera.gameObject.SetActive(true);
                Transform target = FindChildRecursive(gameplayPlayer?.transform, VanzConstants.PlayerCameraRootName) ?? gameplayPlayer?.transform;

                if (target != null)
                {
                    mainGameplayCamera.Follow = target;
                    mainGameplayCamera.LookAt = target;
                    mainGameplayCamera.Priority = 100;
                }
            }

            _activeCutscenePlayer = null;
        }
